  command = parts[0].toLowerCase();
  primaryIntent = 'command';
  confidence = 0.95;
}

const callPatterns = {
  date: /(tomorrow|today|day after tomorrow|on (mon|tue|wed|thu|fri|sat|sun)|\d{1,2}\s+(january|february|march|april|may|june|july|august|september|october|november|december)|\d{1,2}\/\d{1,2}\/\d{4})/i,
  time: /(\d{1,2}:\d{2}|\bat\s+(\d{1,2})\s+(am|pm)?\b|\bat\s+(\d{1,2})\b)/i,
  topic: /about\s+([a-zA-Z0-9\s]{5,40})(?=\s|\.|,|$)/i,
  urgent: /(urgent|important|immediately|ASAP|as soon as possible|critical|today|emergency)/i
};

let extractedCallDate = null;
let extractedCallTime = null;
let extractedTopic = null;
let isCallUrgent = false;

if (primaryIntent === 'callBooking') {
  const dateMatch = text.match(callPatterns.date);
  if (dateMatch) extractedCallDate = dateMatch[0];

  const timeMatch = text.match(callPatterns.time);
  if (timeMatch) extractedCallTime = timeMatch[0];

  const topicMatch = text.match(callPatterns.topic);
  if (topicMatch) extractedTopic = topicMatch[1];

  isCallUrgent = callPatterns.urgent.test(text);
}

const normalizedOutput = {
  original: {
    chat_id: chatId,
    message_id: messageId,
    user_name: `${firstName} ${lastName || ''}`.trim(),
    username: username,
    original_text: text,
    is_business: isBusiness,
    business_connection_id: businessConnectionId,
    reply_to_message_id: messageId 
  },

  intent: {
    primary: primaryIntent,
    all: allIntents,
    confidence: confidence,
    is_command: !!command,
    command_name: command
  },

  call_context: {
    is_booking_request: primaryIntent === 'callBooking',
    requested_date: extractedCallDate,
    requested_time: extractedCallTime,
    topic: extractedTopic,
    is_urgent: isCallUrgent,
    calendly_link: primaryIntent === 'callBooking' ? "https://calendly.com/pitsavello/30min" : null
  },

  debug: {
    summary: `Intent: ${primaryIntent} (${Math.round(confidence * 100)}%) | Call: ${!!extractedCallDate} ${!!extractedCallTime}`,
    timestamp: new Date().toISOString()
  }
};

return [{
  json: normalizedOutput
}];

