CREATE TABLE "calls" (
    id SERIAL PRIMARY KEY,

    user_name VARCHAR(200),
    user_email VARCHAR(200) NOT NULL,
    chat_id BIGINT,

    call_type VARCHAR(100),
    call_date DATE,
    call_time TIME,
    call_start TIMESTAMP,
    call_end TIMESTAMP,
    timezone VARCHAR(50),

    join_url TEXT,
    cancel_url TEXT,
    reschedule_url TEXT,
    calendly_event_uri TEXT,
    calendly_invitee_uri TEXT,

    status VARCHAR(50) DEFAULT 'active',

    raw_payload JSONB,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX idx_calls_email ON "pocket_ai_calls" (user_email);
CREATE INDEX idx_calls_chat_id ON "pocket_ai_calls" (chat_id);
CREATE INDEX idx_calls_date ON "pocket_ai_calls" (call_date);
CREATE INDEX idx_calls_status ON "pocket_ai_calls" (status);
CREATE INDEX idx_calls_created ON "pocket_ai_calls" (created_at DESC);

CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = CURRENT_TIMESTAMP;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS update_calls_updated_at ON "pocket_ai_calls";
CREATE TRIGGER update_calls_updated_at
    BEFORE UPDATE ON "pocket_ai_calls"
    FOR EACH ROW
    EXECUTE FUNCTION update_updated_at_column();
